import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a big number calculator?", a: "A big number calculator performs arithmetic on numbers too large for ordinary calculator precision, keeping exact integer results instead of rounded approximations." },
  { q: "Why do normal calculators fail with very large numbers?", a: "Most calculators use floating-point numbers with limited precision. Very large values can be rounded, displayed in scientific notation, or lose exact digits." },
  { q: "What is arbitrary precision arithmetic?", a: "Arbitrary precision arithmetic uses as many digits as needed instead of a fixed machine-size number, allowing exact results for huge integers." },
  { q: "How large of a number can this calculator handle?", a: "This calculator is designed for integers with hundreds of digits. Extremely long inputs may be limited by browser memory and performance." },
  { q: "What are big numbers used for in real life?", a: "Big numbers appear in cryptography, computer science, astronomy, combinatorics, finance records, and mathematical research." },
];

type Operation = "add" | "subtract" | "multiply" | "divide";
const clean = (value: string) => value.replace(/[,\s]/g, "");
const parseBig = (value: string) => /^-?\d+$/.test(clean(value)) ? BigInt(clean(value)) : null;

export default function BigNumberCalculator() {
  const [a, setA] = useState("123456789123456789123456789");
  const [b, setB] = useState("987654321987654321987654321");
  const [operation, setOperation] = useState<Operation>("add");
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono";

  const result = useMemo(() => {
    const left = parseBig(a);
    const right = parseBig(b);
    if (left === null || right === null) return { value: "Invalid integer input", step: "Use whole numbers only. Commas and spaces are okay." };
    if (operation === "divide" && right === 0n) return { value: "Cannot divide by zero", step: "Division requires a nonzero divisor." };
    const value = operation === "add" ? left + right : operation === "subtract" ? left - right : operation === "multiply" ? left * right : left / right;
    const remainder = operation === "divide" ? left % right : 0n;
    const symbol = operation === "add" ? "+" : operation === "subtract" ? "-" : operation === "multiply" ? "x" : "/";
    return { value: value.toString(), step: `${left.toString()} ${symbol} ${right.toString()} = ${value.toString()}${operation === "divide" && remainder !== 0n ? ` remainder ${remainder.toString()}` : ""}.` };
  }, [a, b, operation]);

  return (
    <>
      <SEOHead title="Free Big Number Calculator Online - Calculate With Extremely Large Numbers Instantly | CalcHive" description="Free online big number calculator. Perform precise addition, subtraction, multiplication and division on extremely large numbers with hundreds of digits instantly. 100% free, no signup required." canonical="/big-number-calculator" keywords="free big number calculator, large number calculator free online, arbitrary precision calculator free, calculate huge numbers free, big integer calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Big Number Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free big number calculator to calculate huge numbers free with exact integer arithmetic.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 gap-4 mb-8">
            <div><label htmlFor="big-a" className="text-sm font-semibold text-foreground block mb-2">Big number A</label><textarea id="big-a" value={a} onChange={(e) => setA(e.target.value)} rows={2} className={inputClass} /></div>
            <div><label htmlFor="operation" className="text-sm font-semibold text-foreground block mb-2">Operation</label><select id="operation" value={operation} onChange={(e) => setOperation(e.target.value as Operation)} className={inputClass}><option value="add">Add</option><option value="subtract">Subtract</option><option value="multiply">Multiply</option><option value="divide">Divide</option></select></div>
            <div><label htmlFor="big-b" className="text-sm font-semibold text-foreground block mb-2">Big number B</label><textarea id="big-b" value={b} onChange={(e) => setB(e.target.value)} rows={2} className={inputClass} /></div>
          </div>
          <motion.div key={`${a}-${b}-${operation}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Exact Result</p><p className="text-2xl sm:text-3xl font-black text-white tracking-tight break-all" data-testid="result-big-number">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground break-all" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate With Extremely Large Numbers for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two whole numbers with hundreds of digits and this big integer calculator free online returns exact arithmetic results.</p><h2 className="text-2xl font-bold text-foreground">Why Normal Calculators Fail With Big Numbers</h2><p className="text-muted-foreground leading-relaxed">Ordinary calculators often use limited floating-point precision, which can round or shorten huge numbers.</p><h2 className="text-2xl font-bold text-foreground">Free Arbitrary Precision Calculator for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this arbitrary precision calculator free for math, cryptography practice, programming, and exact large-number checks.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/big-number-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


